#!/bin/bash
# Fix-Script fuer die restlichen 4 Repos (bescheidboxer + ablesung sind schon done)
# Ausfuehren: cd ~/portal && chmod +x scripts/push-remaining-repos.sh && ./scripts/push-remaining-repos.sh

set -euo pipefail
ORG="alexanderdeibel-Fintutto"
BRANCH="claude/pricing-review"

push_file() {
  local repo="$1" path="$2" b64="$3" msg="$4"
  local sha
  sha=$(gh api "repos/$ORG/$repo/contents/$path?ref=$BRANCH" --jq '.sha' 2>/dev/null || echo "")
  if [ -n "$sha" ]; then
    gh api "repos/$ORG/$repo/contents/$path" -X PUT -f "message=$msg" -f "content=$b64" -f "sha=$sha" -f "branch=$BRANCH" > /dev/null
  else
    gh api "repos/$ORG/$repo/contents/$path" -X PUT -f "message=$msg" -f "content=$b64" -f "branch=$BRANCH" > /dev/null
  fi
  echo "  OK: $path"
}

ensure_branch() {
  local repo="$1"
  local base sha
  base=$(gh api "repos/$ORG/$repo" --jq '.default_branch')
  sha=$(gh api "repos/$ORG/$repo/git/ref/heads/$base" --jq '.object.sha')
  gh api "repos/$ORG/$repo/git/refs" -f "ref=refs/heads/$BRANCH" -f "sha=$sha" 2>/dev/null || true
}

echo "=== 3/6: fintutto-your-financial-compass ==="
ensure_branch "fintutto-your-financial-compass"
push_file "fintutto-your-financial-compass" "src/hooks/useSubscription.ts" \
  "" \
  "Add yearly pricing (20% discount) for Basic and Pro"
echo "  Done!"
echo ""

echo "=== 4/6: mieter ==="
ensure_branch "mieter"
push_file "mieter" "src/hooks/useSubscription.ts" \
  "" \
  "Lower prices (4.99/9.99) for tenant persona, add yearly billing"
echo "  Done!"
echo ""

echo "=== 5/6: hausmeisterPro ==="
ensure_branch "hausmeisterPro"
push_file "hausmeisterPro" "src/config/pricing.ts" \
  "" \
  "Add Enterprise tier (49.99/mo) for large property managers"
echo "  Done!"
echo ""

echo "=== 6/6: vermieter-freude ==="
ensure_branch "vermieter-freude"
push_file "vermieter-freude" "supabase/migrations/20260212120000_referral_rewards.sql" \
  "" \
  "Upgrade referral with real rewards: 1 month free for both sides"
echo "  Done!"
echo ""

echo "============================================"
echo "FERTIG! Alle 6 Repos aktualisiert."
echo "============================================"
